SELECT t.destroy_type, t.app_code, t.doc_code, t.create_user_name, t.create_time, t.status, t.audit_user_name, t.destroy_time, l.create_user_name AS busiCreateUserName, l.create_time AS busiCreateTime, l.busi_no FROM ecm_destroy_task t LEFT JOIN ecm_destroy_list l ON t.id = l.destroy_task_id
t.status = 3 AND t.destroy_type !=3 AND t.destroy_type !=4
AND t.destroy_time >= TO_DATE(#{destroyTimeStart}, 'YYYY-MM-DD HH24:MI:SS') AND t.destroy_time <= TO_DATE(#{destroyTimeEnd}, 'YYYY-MM-DD HH24:MI:SS')
AND t.app_code IN
#{item}
AND t.doc_code IN
#{item}
AND t.destroy_type = #{destroyType}
AND l.busi_no = #{busiNo}
ORDER BY t.destroy_time ASC
